import{Validator,Toast,postJson,restUrl}from"jui";import{t as ts}from"vanilla-signal-i18n";const{success:success,error:error}=Toast,languages={zh:{"Please fill in the title":"请填写标题","Title length cannot be less than 1 character":"标题长度不能小于1个字符","Title length cannot be greater than 100 characters":"标题长度不能大于100个字符","Please fill in the email":"请填写邮箱","Please fill in the correct email":"请填写正确的邮箱","Email cannot contain Chinese characters":"邮箱不能包含中文","Please fill in the content":"请填写内容","Content length cannot be less than 1 character":"内容长度不能小于1个字符","Content length cannot be greater than 500 characters":"内容长度不能大于500个字符"}},t=e=>ts(e,languages),v=new Validator("#contact-form",{rules:{title:{required:!0,minLength:1,maxLength:100},email:{required:!0,email:!0,noChinese:!0},content:{required:!0,minLength:1,maxLength:500}},messages:{title:{required:t("Please fill in the title"),minLength:t("Title length cannot be less than 1 character"),maxLength:t("Title length cannot be greater than 100 characters")},email:{required:t("Please fill in the email"),email:t("Please fill in the correct email"),noChinese:t("Email cannot contain Chinese characters")},content:{required:t("Please fill in the content"),minLength:t("Content length cannot be less than 1 character"),maxLength:t("Content length cannot be greater than 500 characters")}}},!0),form=document.querySelector("#contact-form");form.addEventListener("submit",e=>{if(e.preventDefault(),!v.runtime.valid&&v.runtime.message)error(v.runtime.message);else{const e=new FormData(form),t={};for(const[n,a]of e.entries())"title"!==n&&"email"!==n&&"content"!==n?(t.ext||(t.ext={}),t.ext[n]=a):t[n]=a;const n=e=>restUrl+"/api/contact/v1"+e;postJson(n("/form"),t).then(e=>{e.success?(success(e.message),v.reset()):error(e.message)}).catch(e=>{error(e.message)})}}),form.addEventListener("reset",()=>{v.reset()});